import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { useRtlSprintTimelineBoardCardChange, useRtlSprintTimelineBoardLoadMore } from "./useCardChange";
import type { KanbanCardData } from "../../components/kanban/types";

/**
 * خارطة الطريق · ٢٠٢٦
 * اسحب البطاقات بين الأرباع لتعديل الجدول الزمني
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 */
export default function RtlSprintTimelineBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const handleCardChange = useRtlSprintTimelineBoardCardChange();
  const handleLoadMore = useRtlSprintTimelineBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={boardConfig}
        cards={cards}
        onCardsChange={setCards}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

import type { KanbanBuilderConfig } from "../../components/kanban/types";

/** Static configuration. All fields are typed and validated. */
export const boardConfig: KanbanBuilderConfig = {
  "title": "خارطة الطريق · ٢٠٢٦",
  "subtitle": "اسحب البطاقات بين الأرباع لتعديل الجدول الزمني",
  "layout": "timeline",
  "columns": [
    {
      "id": "q1",
      "title": "الربع الأول",
      "color": "blue"
    },
    {
      "id": "q2",
      "title": "الربع الثاني",
      "color": "amber"
    },
    {
      "id": "q3",
      "title": "الربع الثالث",
      "color": "purple"
    },
    {
      "id": "q4",
      "title": "الربع الرابع",
      "color": "emerald"
    }
  ],
  "visibleFields": [
    "priority",
    "tags",
    "assignee",
    "progress",
    "estimate"
  ],
  "enableDnd": true,
  "enableAddCard": true,
  "enableWipLimits": false,
  "showColumnTotals": true,
  "compactCards": false,
  "direction": "rtl",
  "reduceMotion": false,
  "cardClickAction": {
    "dialogTitle": "{{row.title}}",
    "dialogDescription": "Owner: {{row.assignee}} · {{row.estimate}}",
    "dialogWidthClass": "max-w-xl",
    "dialogTemplate": "<div class=\"space-y-3 text-right\" dir=\"rtl\">\n  <div class=\"flex items-center justify-end gap-2\">\n    {{#each row.tags}}<span class=\"rounded bg-secondary px-2 py-0.5 text-[10px]\">{{.}}</span>{{/each}}\n  </div>\n  <p class=\"text-sm text-muted-foreground\">المسؤول: <strong>{{row.assignee}}</strong></p>\n  <p class=\"text-sm text-muted-foreground\">التقدير: <strong>{{row.estimate}}</strong></p>\n  <div class=\"rounded-md border bg-muted/30 p-3 text-xs\">\n    <div class=\"mb-1 text-muted-foreground\">نسبة الإنجاز</div>\n    <div class=\"h-2 w-full overflow-hidden rounded bg-background\">\n      <div class=\"h-full bg-primary\" style=\"width: {{row.progress}}%\"></div>\n    </div>\n  </div>\n</div>"
  }
};

import { useCallback } from "react";
import type { KanbanCardChangeEvent, KanbanLoadMoreEvent } from "../../components/kanban/types";

/**
 * Called whenever a card is dropped into a new position via DnD.
 * Replace the body with your real backend call (e.g. fetch PATCH).
 *
 * Example:
 *   await fetch(`/api/cards/${event.card.id}`, {
 *     method: "PATCH",
 *     body: JSON.stringify({ columnId: event.toColumnId, position: event.toIndex }),
 *   });
 */
export function useRtlSprintTimelineBoardCardChange() {
  return useCallback((event: KanbanCardChangeEvent) => {
    // TODO: persist the change to your backend.
    console.log("[kanban] card moved:", event);
  }, []);
}

export function useRtlSprintTimelineBoardLoadMore() {
  return useCallback(async (event: KanbanLoadMoreEvent) => {
    // TODO: fetch the next page for event.columnId/event.cursor and append it to cards.
    console.log("[kanban] load more:", event);
  }, []);
}
